     1→# LogAnalyzer.Tests.ps1
     2→# TDD test suite for the Log File Analyzer
     3→# Tests are written FIRST (red), then implementation follows (green)
     4→
     5→# Ensure Pester 5.x is available
     6→$pesterModule = Get-Module -ListAvailable -Name Pester | Sort-Object Version -Descending | Select-Object -First 1
     7→if (-not $pesterModule -or $pesterModule.Version.Major -lt 5) {
     8→    Write-Host "Installing Pester 5.x..." -ForegroundColor Yellow
     9→    Install-Module -Name Pester -Force -SkipPublisherCheck -MinimumVersion 5.0.0 -Scope CurrentUser
    10→}
    11→Import-Module Pester -MinimumVersion 5.0.0
    12→
    13→# Source the implementation (will fail until LogAnalyzer.ps1 exists)
    14→. "$PSScriptRoot/LogAnalyzer.ps1"
    15→
    16→# ============================================================
    17→# RED PHASE 1: Parse syslog-style log lines
    18→# Format: "2024-01-15 10:23:45 LEVEL component: message"
    19→# ============================================================
    20→Describe "Parse-SyslogLine" {
    21→    It "parses a syslog ERROR line correctly" {
    22→        $line = "2024-01-15 10:23:45 ERROR auth: Login failed for user admin"
    23→        $result = Parse-SyslogLine -Line $line
    24→
    25→        $result | Should -Not -BeNullOrEmpty
    26→        $result.Timestamp | Should -Be ([datetime]"2024-01-15 10:23:45")
    27→        $result.Level     | Should -Be "ERROR"
    28→        $result.Component | Should -Be "auth"
    29→        $result.Message   | Should -Be "Login failed for user admin"
    30→        $result.Format    | Should -Be "syslog"
    31→    }
    32→
    33→    It "parses a syslog WARNING line correctly" {
    34→        $line = "2024-01-15 10:24:00 WARNING disk: Disk usage at 90%"
    35→        $result = Parse-SyslogLine -Line $line
    36→
    37→        $result.Level   | Should -Be "WARNING"
    38→        $result.Message | Should -Be "Disk usage at 90%"
    39→    }
    40→
    41→    It "parses a syslog INFO line correctly" {
    42→        $line = "2024-01-15 10:25:00 INFO app: Server started on port 8080"
    43→        $result = Parse-SyslogLine -Line $line
    44→
    45→        $result.Level | Should -Be "INFO"
    46→    }
    47→
    48→    It "returns null for lines that don't match syslog format" {
    49→        $line = "this is not a syslog line"
    50→        $result = Parse-SyslogLine -Line $line
    51→        $result | Should -BeNullOrEmpty
    52→    }
    53→}
    54→
    55→# ============================================================
    56→# RED PHASE 2: Parse JSON-structured log lines
    57→# Format: {"timestamp":"...","level":"...","component":"...","message":"..."}
    58→# ============================================================
    59→Describe "Parse-JsonLogLine" {
    60→    It "parses a JSON ERROR line correctly" {
    61→        $line = '{"timestamp":"2024-01-15T10:23:45Z","level":"ERROR","component":"auth","message":"Authentication failed"}'
    62→        $result = Parse-JsonLogLine -Line $line
    63→
    64→        $result | Should -Not -BeNullOrEmpty
    65→        $result.Level     | Should -Be "ERROR"
    66→        $result.Component | Should -Be "auth"
    67→        $result.Message   | Should -Be "Authentication failed"
    68→        $result.Format    | Should -Be "json"
    69→    }
    70→
    71→    It "parses a JSON WARNING line correctly" {
    72→        $line = '{"timestamp":"2024-01-15T10:24:00Z","level":"WARN","component":"db","message":"Slow query detected"}'
    73→        $result = Parse-JsonLogLine -Line $line
    74→
    75→        # WARN should be normalized to WARNING
    76→        $result.Level | Should -Be "WARNING"
    77→    }
    78→
    79→    It "returns null for lines that are not valid JSON" {
    80→        $line = "not json at all"
    81→        $result = Parse-JsonLogLine -Line $line
    82→        $result | Should -BeNullOrEmpty
    83→    }
    84→
    85→    It "returns null for JSON without required fields" {
    86→        $line = '{"foo":"bar"}'
    87→        $result = Parse-JsonLogLine -Line $line
    88→        $result | Should -BeNullOrEmpty
    89→    }
    90→}
    91→
    92→# ============================================================
    93→# RED PHASE 3: Parse a mixed log file (auto-detect format per line)
    94→# ============================================================
    95→Describe "Parse-LogFile" {
    96→    BeforeAll {
    97→        # Create a temp file with mixed-format log content
    98→        $script:TempLogPath = [System.IO.Path]::GetTempFileName()
    99→        $mixedLog = @"
   100→2024-01-15 10:00:00 INFO app: Application starting
   101→2024-01-15 10:00:05 ERROR auth: Login failed for user admin
   102→{"timestamp":"2024-01-15T10:00:10Z","level":"ERROR","component":"db","message":"Connection timeout"}
   103→2024-01-15 10:00:15 WARNING disk: Disk usage at 85%
   104→{"timestamp":"2024-01-15T10:00:20Z","level":"WARN","component":"api","message":"Rate limit approaching"}
   105→2024-01-15 10:00:25 INFO app: Request processed
   106→this is a malformed line that should be skipped
   107→{"timestamp":"2024-01-15T10:00:30Z","level":"ERROR","component":"auth","message":"Login failed for user admin"}
   108→"@
   109→        Set-Content -Path $script:TempLogPath -Value $mixedLog
   110→    }
   111→
   112→    AfterAll {
   113→        Remove-Item -Path $script:TempLogPath -ErrorAction SilentlyContinue
   114→    }
   115→
   116→    It "returns a collection of parsed log entries" {
   117→        $results = Parse-LogFile -Path $script:TempLogPath
   118→        $results | Should -Not -BeNullOrEmpty
   119→    }
   120→
   121→    It "correctly parses both syslog and JSON lines" {
   122→        $results = Parse-LogFile -Path $script:TempLogPath
   123→        $syslogEntries = $results | Where-Object { $_.Format -eq "syslog" }
   124→        $jsonEntries   = $results | Where-Object { $_.Format -eq "json" }
   125→
   126→        $syslogEntries.Count | Should -Be 4
   127→        $jsonEntries.Count   | Should -Be 3
   128→    }
   129→
   130→    It "skips malformed lines without throwing" {
   131→        # Total valid lines = 7 (4 syslog + 3 json), 1 malformed
   132→        $results = Parse-LogFile -Path $script:TempLogPath
   133→        $results.Count | Should -Be 7
   134→    }
   135→
   136→    It "throws a meaningful error when file does not exist" {
   137→        { Parse-LogFile -Path "C:\nonexistent\file.log" } | Should -Throw "*not found*"
   138→    }
   139→}
   140→
   141→# ============================================================
   142→# RED PHASE 4: Filter errors and warnings
   143→# ============================================================
   144→Describe "Get-ErrorsAndWarnings" {
   145→    BeforeAll {
   146→        $script:AllEntries = @(
   147→            [PSCustomObject]@{ Level = "INFO";    Message = "App started";         Component = "app";  Timestamp = [datetime]"2024-01-15 10:00:00"; Format = "syslog" }
   148→            [PSCustomObject]@{ Level = "ERROR";   Message = "Login failed";        Component = "auth"; Timestamp = [datetime]"2024-01-15 10:00:05"; Format = "syslog" }
   149→            [PSCustomObject]@{ Level = "ERROR";   Message = "Connection timeout";  Component = "db";   Timestamp = [datetime]"2024-01-15 10:00:10"; Format = "json" }
   150→            [PSCustomObject]@{ Level = "WARNING"; Message = "Disk usage at 85%";   Component = "disk"; Timestamp = [datetime]"2024-01-15 10:00:15"; Format = "syslog" }
   151→            [PSCustomObject]@{ Level = "WARNING"; Message = "Rate limit approaching"; Component = "api"; Timestamp = [datetime]"2024-01-15 10:00:20"; Format = "json" }
   152→            [PSCustomObject]@{ Level = "INFO";    Message = "Request processed";   Component = "app";  Timestamp = [datetime]"2024-01-15 10:00:25"; Format = "syslog" }
   153→        )
   154→    }
   155→
   156→    It "returns only ERROR and WARNING entries" {
   157→        $filtered = Get-ErrorsAndWarnings -Entries $script:AllEntries
   158→        $filtered.Count | Should -Be 4
   159→    }
   160→
   161→    It "excludes INFO entries" {
   162→        $filtered = Get-ErrorsAndWarnings -Entries $script:AllEntries
   163→        $infoEntries = $filtered | Where-Object { $_.Level -eq "INFO" }
   164→        $infoEntries | Should -BeNullOrEmpty
   165→    }
   166→
   167→    It "returns empty array when no errors or warnings exist" {
   168→        $infoOnly = $script:AllEntries | Where-Object { $_.Level -eq "INFO" }
   169→        $filtered = Get-ErrorsAndWarnings -Entries $infoOnly
   170→        $filtered.Count | Should -Be 0
   171→    }
   172→}
   173→
   174→# ============================================================
   175→# RED PHASE 5: Build frequency table (group by error type/message)
   176→# ============================================================
   177→Describe "Build-FrequencyTable" {
   178→    BeforeAll {
   179→        $script:ErrorEntries = @(
   180→            [PSCustomObject]@{ Level = "ERROR";   Message = "Login failed";       Component = "auth"; Timestamp = [datetime]"2024-01-15 10:00:05" }
   181→            [PSCustomObject]@{ Level = "ERROR";   Message = "Login failed";       Component = "auth"; Timestamp = [datetime]"2024-01-15 10:01:00" }
   182→            [PSCustomObject]@{ Level = "ERROR";   Message = "Login failed";       Component = "auth"; Timestamp = [datetime]"2024-01-15 10:05:00" }
