   184→            [PSCustomObject]@{ Level = "WARNING"; Message = "Disk usage at 85%";  Component = "disk"; Timestamp = [datetime]"2024-01-15 10:00:15" }
   185→            [PSCustomObject]@{ Level = "WARNING"; Message = "Disk usage at 85%";  Component = "disk"; Timestamp = [datetime]"2024-01-15 10:10:00" }
   186→        )
